def gen(rng, size):
    n = rng.randint(0, max(1, min(size, 200)))
    vals = rng.sample(range(-1000000, 1000000), n) if n else []

    class N:
        __slots__ = ("v", "l", "r")

        def __init__(self, v):
            self.v = v
            self.l = None
            self.r = None

    root = None
    for v in vals:
        if root is None:
            root = N(v)
            continue
        cur = root
        while True:
            if v < cur.v:
                if cur.l is None:
                    cur.l = N(v)
                    break
                cur = cur.l
            else:
                if cur.r is None:
                    cur.r = N(v)
                    break
                cur = cur.r

    out = []
    if root is not None:
        queue = [root]
        while queue:
            node = queue.pop(0)
            if node is None:
                out.append(None)
                continue
            out.append(node.v)
            queue.append(node.l)
            queue.append(node.r)
        while out and out[-1] is None:
            out.pop()
    return [out]

