class Codec:
    def serialize(self, root):
        tokens = []

        def walk(node):
            if node is None:
                tokens.append('#')
                return
            tokens.append(str(node.val))
            walk(node.left)
            walk(node.right)

        walk(root)
        return ','.join(tokens)

    def deserialize(self, data):
        stream = iter(data.split(','))

        def rebuild():
            token = next(stream)
            if token == '#':
                return None
            node = TreeNode(int(token))
            node.left = rebuild()
            node.right = rebuild()
            return node

        return rebuild()

