class Codec:
    def serialize(self, root):
        vals = []

        def preorder(node):
            if node:
                vals.append(node.val)
                preorder(node.left)
                preorder(node.right)

        preorder(root)
        return ' '.join(map(str, vals))

    def deserialize(self, data):
        if not data:
            return None
        vals = list(map(int, data.split()))
        self._i = 0

        def build(lower, upper):
            if self._i == len(vals) or not (lower < vals[self._i] < upper):
                return None
            val = vals[self._i]
            self._i += 1
            node = TreeNode(val)
            node.left = build(lower, val)
            node.right = build(val, upper)
            return node

        return build(float('-inf'), float('inf'))

