var serialize = function(root) {
    const vals = [];
    const preorder = (node) => {
        if (!node) return;
        vals.push(node.val);
        preorder(node.left);
        preorder(node.right);
    };
    preorder(root);
    return vals.join(' ');
};

var deserialize = function(data) {
    if (!data) return null;
    const vals = data.split(' ').map(Number);
    let i = 0;
    const build = (lower, upper) => {
        if (i === vals.length || !(vals[i] > lower && vals[i] < upper)) return null;
        const val = vals[i];
        i += 1;
        const node = new TreeNode(val);
        node.left = build(lower, val);
        node.right = build(val, upper);
        return node;
    };
    return build(-Infinity, Infinity);
};
